/**
 * Integration tests for the full notification pipeline.
 *
 * Tests the end-to-end flow:
 *   Domain Event → EventBus → NotificationService → Adapter (email/sms/webhook)
 *   → lifecycle events → NotificationHistoryService → NotificationLogRepository
 *
 * Also tests preferences integration: PreferencesService suppresses notifications
 * when a channel or category is disabled.
 *
 * These tests exercise the real implementations (no mocks) in stub mode to
 * validate that the full stack works together correctly.
 */

import { describe, it, expect, beforeEach } from 'vitest';

// Event system
import { EventBus } from '../../src/events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../../src/events/event-types.js';

// Services
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';

// Adapters
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';

// Repositories
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';

// Database
import { Database } from '../../src/utils/database.js';

// Models
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

// ---------------------------------------------------------------------------
// Test Helpers
// ---------------------------------------------------------------------------

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

// ---------------------------------------------------------------------------
// Integration Tests
// ---------------------------------------------------------------------------

describe('Notification Pipeline — Integration', () => {
  let db: Database;
  let eventBus: EventBus;

  // Repositories
  let logRepo: NotificationLogRepository;
  let prefsRepo: PreferencesRepository;

  // Services
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let preferencesService: PreferencesService;

  // Adapters (all in stub mode)
  let emailAdapter: EmailAdapter;
  let smsAdapter: SmsAdapter;
  let webhookAdapter: WebhookAdapter;

  beforeEach(() => {
    // Reset all ID counters
    resetNotificationIdCounter();
    resetNotificationLogIdCounter();
    resetPreferencesIdCounter();

    // Fresh database and event bus for each test
    db = new Database();
    eventBus = new EventBus();

    // Repositories
    logRepo = new NotificationLogRepository(db);
    prefsRepo = new PreferencesRepository(db);

    // Services — order matters: NotificationService and HistoryService both
    // register event handlers on the EventBus during construction, so the
    // EventBus must be created first.
    notificationService = new NotificationService(eventBus);
    historyService = new NotificationHistoryService(eventBus, logRepo);
    preferencesService = new PreferencesService(prefsRepo);

    // Wire preferences into the notification service
    notificationService.setPreferencesService(preferencesService);

    // Adapters — all in stub mode for integration tests
    emailAdapter = new EmailAdapter({ stubMode: true });
    smsAdapter = new SmsAdapter({ stubMode: true });
    webhookAdapter = new WebhookAdapter({
      stubMode: true,
      url: 'https://hooks.example.com/notify',
    });

    // Register adapters
    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);
  });

  // -------------------------------------------------------------------------
  // Email Channel — End-to-End
  // -------------------------------------------------------------------------

  describe('Email channel end-to-end', () => {
    it('should deliver an email notification when user has email enabled', async () => {
      const user = makeUser();
      const order = makeOrder();

      // User preferences: email enabled (default)
      preferencesService.createPreferences({
        userId: user.id,
        email: { enabled: true },
      });

      // Trigger: order:created → NotificationService → EmailAdapter
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order,
        user,
        timestamp: new Date(),
      });

      // 1. NotificationService recorded the notification
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.status).toBe('sent');
      expect(notifications[0]!.channel).toBe('email');
      expect(notifications[0]!.type).toBe('order_confirmation');
      expect(notifications[0]!.recipient).toBe('alice@example.com');

      // 2. EmailAdapter received and recorded the email
      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.to).toBe('alice@example.com');
      expect(sentEmails[0]!.subject).toContain('Order Confirmation');
      expect(sentEmails[0]!.notificationType).toBe('order_confirmation');
      // Template should have rendered HTML
      expect(sentEmails[0]!.html).toContain('Order Confirmed');

      // 3. NotificationHistoryService logged the delivery
      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.deliveryStatus).toBe('sent');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.recipient).toBe('alice@example.com');
      expect(logs[0]!.notificationId).toBe(notifications[0]!.id);
    });

    it('should deliver welcome email on user:created event', async () => {
      const user = makeUser({ id: 'user-2', name: 'Bob', email: 'bob@example.com' });

      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user,
        timestamp: new Date(),
      });

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.type).toBe('welcome');
      expect(notifications[0]!.status).toBe('sent');
      expect(notifications[0]!.subject).toContain('Welcome');

      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.to).toBe('bob@example.com');
      expect(sentEmails[0]!.html).toContain('Welcome');

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.type).toBe('welcome');
      expect(logs[0]!.deliveryStatus).toBe('sent');
    });

    it('should deliver account_updated email on user:updated event', async () => {
      const user = makeUser();

      await eventBus.emit<UserUpdatedEvent>({
        type: 'user:updated',
        user,
        changes: ['name', 'email'],
        timestamp: new Date(),
      });

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.type).toBe('account_updated');
      expect(notifications[0]!.status).toBe('sent');
      expect(notifications[0]!.body).toContain('name');
      expect(notifications[0]!.body).toContain('email');
      expect(notifications[0]!.priority).toBe('low');

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.type).toBe('account_updated');
    });

    it('should deliver order_status_update with high priority for cancelled orders', async () => {
      const order = makeOrder({ status: 'cancelled' });

      await eventBus.emit<OrderStatusChangedEvent>({
        type: 'order:status-changed',
        order,
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      });

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.priority).toBe('high');
      expect(notifications[0]!.type).toBe('order_status_update');
      expect(notifications[0]!.status).toBe('sent');

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.priority).toBe('high');
    });
  });

  // -------------------------------------------------------------------------
  // SMS Channel — End-to-End
  // -------------------------------------------------------------------------

  describe('SMS channel end-to-end', () => {
    it('should deliver an SMS notification when user has SMS enabled', async () => {
      const user = makeUser();

      // Create preferences with SMS enabled
      preferencesService.createPreferences({
        userId: user.id,
        sms: { enabled: true },
      });

      // Send directly via SMS channel
      const record = await notificationService.send({
        type: 'order_confirmation',
        recipient: '+15551234567',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        channel: 'sms',
        priority: 'normal',
        metadata: { userId: user.id },
      });

      // 1. Notification was recorded as sent
      expect(record.status).toBe('sent');
      expect(record.channel).toBe('sms');

      // 2. SmsAdapter received and recorded the SMS
      const sentMessages = smsAdapter.getSentMessages();
      expect(sentMessages).toHaveLength(1);
      expect(sentMessages[0]!.to).toBe('+15551234567');
      expect(sentMessages[0]!.body).toContain('Order Confirmation');

      // 3. History logged the delivery
      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.channel).toBe('sms');
      expect(logs[0]!.deliveryStatus).toBe('sent');
      expect(logs[0]!.notificationId).toBe(record.id);
    });

    it('should format SMS messages within character limit', async () => {
      const record = await notificationService.send({
        type: 'order_confirmation',
        recipient: '+15551234567',
        subject: 'Order Confirmation',
        body: 'A'.repeat(200),
        channel: 'sms',
        priority: 'normal',
      });

      expect(record.status).toBe('sent');
      const sentMessages = smsAdapter.getSentMessages();
      expect(sentMessages).toHaveLength(1);
      // Default max length is 160
      expect(sentMessages[0]!.body.length).toBeLessThanOrEqual(160);
    });
  });

  // -------------------------------------------------------------------------
  // Webhook Channel — End-to-End
  // -------------------------------------------------------------------------

  describe('Webhook channel end-to-end', () => {
    it('should deliver a webhook notification', async () => {
      const user = makeUser();

      // Create preferences with webhook enabled
      preferencesService.createPreferences({
        userId: user.id,
        webhook: { enabled: true, url: 'https://hooks.example.com/notify' },
      });

      const record = await notificationService.send({
        type: 'order_confirmation',
        recipient: user.email,
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        channel: 'webhook',
        priority: 'normal',
